import React from 'react';
import Navigation from './components/Navigation';
import Hero from './components/Hero';
import Features from './components/Features';
import MobileSuite from './components/MobileSuite';
import Testimonials from './components/Testimonials';
import ContactForm from './components/ContactForm';
import Footer from './components/Footer';
import UnicornScene from 'unicornstudio-react';
import { useScrollReveal } from './hooks/useScrollReveal';

function App() {
  useScrollReveal();

  return (
    <div className="min-h-screen">
      {/* Background (component) added by Aura */}
      <div 
        className="aura-background-component fixed top-0 w-full h-screen mix-blend-screen brightness-50 opacity-50 saturate-0 z-10 pointer-events-none" 
        style={{ maskImage: 'linear-gradient(to bottom, transparent, black 0%, black 80%, transparent)', WebkitMaskImage: 'linear-gradient(to bottom, transparent, black 0%, black 80%, transparent)' }}
      >
        <div className="aura-background-component top-0 w-full -z-10 absolute h-full">
          <UnicornScene projectId="bKN5upvoulAmWvInmHza" sdkUrl="https://cdn.jsdelivr.net/gh/hiunicornstudio/unicornstudio.js@v1.4.29/dist/unicornStudio.umd.js" className="absolute w-full h-full left-0 top-0 -z-10" />
        </div>
      </div>

      {/* Progressive Blur Top */}
      <div className="gradient-blur">
        <div></div>
        <div></div>
        <div></div>
        <div></div>
        <div></div>
        <div></div>
      </div>

      <Navigation />

      <main>
        <Hero />
        <Features />
        <MobileSuite />
        <Testimonials />
        <ContactForm />
      </main>

      <Footer />
    </div>
  );
}

export default App;

@tailwind base;
@tailwind components;
@tailwind utilities;

@layer utilities {
  .animate-on-scroll { 
    animation-play-state: paused !important; 
  }
  .animate-on-scroll.animate { 
    animation-play-state: running !important; 
  }
}

/* Animations */
@keyframes fadeSlideIn {
  0% {
    opacity: 0;
    transform: translateY(30px);
    filter: blur(8px);
  }
  100% {
    opacity: 1;
    transform: translateY(0);
    filter: blur(0px);
  }
}

@keyframes columnReveal {
  0% {
    clip-path: inset(0 0 100% 0);
    opacity: 0;
  }
  100% {
    clip-path: inset(0 0 0% 0);
    opacity: 1;
  }
}

@keyframes border-spin { 
  to { --gradient-angle: 360deg; } 
}

@keyframes shimmer { 
  to { transform: translate(-50%, -50%) rotate(360deg); } 
}

@keyframes breathe {
  0%, 100% { transform: translate(-50%, -50%) scale(1); }
  50% { transform: translate(-50%, -50%) scale(1.20); }
}

@keyframes beam-spin { 
  to { transform: rotate(360deg); } 
}

@keyframes dots-move { 
  0% { background-position: 0 0; } 
  100% { background-position: 24px 24px; } 
}

@keyframes typing { 
  from { width: 0 } 
  to { width: 100% } 
}

@keyframes blink-caret { 
  50% { border-color: transparent } 
}

@keyframes slideDown { 
  from { opacity: 0; transform: translateY(-10px); } 
  to { opacity: 1; transform: translateY(0); } 
}

@keyframes carousel-fade {
  0% { opacity: 0; z-index: 10; }
  5% { opacity: 1; z-index: 20; }
  28% { opacity: 1; z-index: 20; }
  33% { opacity: 0; z-index: 10; }
  100% { opacity: 0; z-index: 10; }
}

@keyframes infinite-scroll {
  0% { transform: translateX(0); }
  100% { transform: translateX(-50%); }
}

/* Custom Classes */
.col-anim {
  animation: columnReveal 1.4s cubic-bezier(0.16, 1, 0.3, 1) backwards;
  will-change: clip-path;
}

.delay-1 { animation-delay: 0.1s; }
.delay-2 { animation-delay: 0.2s; }
.delay-3 { animation-delay: 0.3s; }
.delay-4 { animation-delay: 0.4s; }
.delay-5 { animation-delay: 0.5s; }
.delay-6 { animation-delay: 0.6s; }
.delay-7 { animation-delay: 0.7s; }

.animate-infinite-scroll {
  animation: infinite-scroll 40s linear infinite;
}

.group:hover .animate-infinite-scroll {
  animation-play-state: paused;
}

.type-writer {
  overflow: hidden;
  white-space: nowrap;
  border-right: 2px solid #10b981;
  width: 0;
  animation: typing 1.5s steps(30, end) 2.5s forwards, blink-caret 0.75s step-end infinite;
}

.animate-carousel {
  animation: carousel-fade 15s infinite;
  position: absolute;
  inset: 0;
  height: 100%;
  width: 100%;
}

.carousel-container {
  display: grid;
  grid-template-columns: 1fr;
  grid-template-rows: 1fr;
  min-height: 600px;
}

@media (min-width: 1024px) {
  .carousel-container {
    min-height: auto;
  }
}

.carousel-card {
  grid-area: 1 / 1 / 2 / 2;
}

/* Border Gradient Shared Style */
[style*="--border-gradient"]::before {
  content: "";
  position: absolute;
  inset: 0;
  padding: 1px;
  border-radius: var(--border-radius-before, inherit);
  -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  -webkit-mask-composite: xor;
  mask-composite: exclude;
  background: var(--border-gradient);
  pointer-events: none;
}

/* Progressive Blur CSS */
.gradient-blur {
  position: fixed;
  z-index: 5;
  inset: 0 0 auto 0;
  height: 12%;
  pointer-events: none;
}
.gradient-blur>div, .gradient-blur::before, .gradient-blur::after { position: absolute; inset: 0; }
.gradient-blur::before { content: ""; z-index: 1; backdrop-filter: blur(0.5px); mask: linear-gradient(to top, rgba(0, 0, 0, 0) 0%, rgba(0, 0, 0, 1) 12.5%, rgba(0, 0, 0, 1) 25%, rgba(0, 0, 0, 0) 37.5%); }
.gradient-blur>div:nth-of-type(1) { z-index: 2; backdrop-filter: blur(1px); mask: linear-gradient(to top, rgba(0, 0, 0, 0) 12.5%, rgba(0, 0, 0, 1) 25%, rgba(0, 0, 0, 1) 37.5%, rgba(0, 0, 0, 0) 50%); }
.gradient-blur>div:nth-of-type(2) { z-index: 3; backdrop-filter: blur(2px); mask: linear-gradient(to top, rgba(0, 0, 0, 0) 25%, rgba(0, 0, 0, 1) 37.5%, rgba(0, 0, 0, 1) 50%, rgba(0, 0, 0, 0) 62.5%); }
.gradient-blur>div:nth-of-type(3) { z-index: 4; backdrop-filter: blur(4px); mask: linear-gradient(to top, rgba(0, 0, 0, 0) 37.5%, rgba(0, 0, 0, 1) 50%, rgba(0, 0, 0, 1) 62.5%, rgba(0, 0, 0, 0) 75%); }
.gradient-blur>div:nth-of-type(4) { z-index: 5; backdrop-filter: blur(8px); mask: linear-gradient(to top, rgba(0, 0, 0, 0) 50%, rgba(0, 0, 0, 1) 62.5%, rgba(0, 0, 0, 1) 75%, rgba(0, 0, 0, 0) 87.5%); }
.gradient-blur>div:nth-of-type(5) { z-index: 6; backdrop-filter: blur(16px); mask: linear-gradient(to top, rgba(0, 0, 0, 0) 62.5%, rgba(0, 0, 0, 1) 75%, rgba(0, 0, 0, 1) 87.5%, rgba(0, 0, 0, 0) 100%); }
.gradient-blur>div:nth-of-type(6) { z-index: 7; backdrop-filter: blur(32px); mask: linear-gradient(to top, rgba(0, 0, 0, 0) 75%, rgba(0, 0, 0, 1) 87.5%, rgba(0, 0, 0, 1) 100%); }
.gradient-blur::after { content: ""; z-index: 8; backdrop-filter: blur(64px); mask: linear-gradient(to top, rgba(0, 0, 0, 0) 87.5%, rgba(0, 0, 0, 1) 100%); }

